//! Self-deployment of ERC-8004 contracts.
//!
//! Embeds compiled Solidity bytecode for the three registries and deploys
//! them on-chain. Used by the node to bootstrap its own identity infrastructure.

use alloy::network::TransactionBuilder;
use alloy::primitives::{Address, Bytes};
use alloy::providers::Provider;
use std::time::Duration;
use x402::X402Error;

// Compiled bytecode for minimal ERC-8004 contracts (Solidity 0.8.24).
// Source lives in the plan doc — these are pre-compiled for deployment.

const IDENTITY_BYTECODE: &str = "";

const REPUTATION_BYTECODE: &str = "";

const VALIDATION_BYTECODE: &str = "";

/// Deploy a contract from raw bytecode. Returns the deployed contract address.
async fn deploy_bytecode<P: Provider>(
    provider: &P,
    bytecode_hex: &str,
    label: &str,
) -> Result<Address, X402Error> {
    let bytecode = alloy::hex::decode(bytecode_hex.strip_prefix("0x").unwrap_or(bytecode_hex))
        .map_err(|e| X402Error::ChainError(format!("{label} bytecode decode failed: {e}")))?;

    let tx =
        alloy::rpc::types::TransactionRequest::default().with_deploy_code(Bytes::from(bytecode));

    let pending = tokio::time::timeout(Duration::from_secs(30), provider.send_transaction(tx))
        .await
        .map_err(|_| X402Error::ChainError(format!("{label} deploy send timed out after 30s")))?
        .map_err(|e| X402Error::ChainError(format!("{label} deploy send failed: {e}")))?;

    let receipt = tokio::time::timeout(Duration::from_secs(60), pending.get_receipt())
        .await
        .map_err(|_| X402Error::ChainError(format!("{label} deploy receipt timed out after 60s")))?
        .map_err(|e| X402Error::ChainError(format!("{label} deploy receipt failed: {e}")))?;

    if !receipt.status() {
        return Err(X402Error::ChainError(format!("{label} deploy reverted")));
    }

    receipt.contract_address.ok_or_else(|| {
        X402Error::ChainError(format!(
            "{label} deploy succeeded but no contract address in receipt"
        ))
    })
}

/// Deployed registry addresses.
#[derive(Debug, Clone)]
pub struct DeployedRegistries {
    pub identity: Address,
    pub reputation: Address,
    pub validation: Address,
}

/// Deploy the identity registry contract.
pub async fn deploy_identity_registry<P: Provider>(provider: &P) -> Result<Address, X402Error> {
    let addr = deploy_bytecode(provider, IDENTITY_BYTECODE, "AgentIdentity").await?;
    tracing::info!(address = %addr, "Deployed AgentIdentity registry");
    Ok(addr)
}

/// Deploy the reputation registry contract.
pub async fn deploy_reputation_registry<P: Provider>(provider: &P) -> Result<Address, X402Error> {
    let addr = deploy_bytecode(provider, REPUTATION_BYTECODE, "AgentReputation").await?;
    tracing::info!(address = %addr, "Deployed AgentReputation registry");
    Ok(addr)
}

/// Deploy the validation registry contract.
pub async fn deploy_validation_registry<P: Provider>(provider: &P) -> Result<Address, X402Error> {
    let addr = deploy_bytecode(provider, VALIDATION_BYTECODE, "AgentValidation").await?;
    tracing::info!(address = %addr, "Deployed AgentValidation registry");
    Ok(addr)
}

/// Deploy all three ERC-8004 registries. Returns their addresses.
pub async fn deploy_all<P: Provider>(provider: &P) -> Result<DeployedRegistries, X402Error> {
    let identity = deploy_identity_registry(provider).await?;
    let reputation = deploy_reputation_registry(provider).await?;
    let validation = deploy_validation_registry(provider).await?;
    Ok(DeployedRegistries {
        identity,
        reputation,
        validation,
    })
}
